void mc_testbench::capture_IN( ac_channel<ac_int<10, true > > &data_in,  ac_int<7, true > coeffs[32][4],  ac_channel<ac_int<5, false > > &coeff_addr,  ac_channel<ac_int<19, true > > &result)
{
   that->capture_data_in(data_in);
   that->capture_coeffs(coeffs);
   that->capture_coeff_addr(coeff_addr);
   that->remaining_result_golden =  result.ac_channel<ac_int<19, true > >::debug_size();
}
// ============================================
// Function: capture_OUT
// --------------------------------------------

void mc_testbench::capture_OUT( ac_channel<ac_int<10, true > > &data_in,  ac_int<7, true > coeffs[32][4],  ac_channel<ac_int<5, false > > &coeff_addr,  ac_channel<ac_int<19, true > > &result)
{
   that->remaining_ccs_data_in =  data_in.ac_channel<ac_int<10, true > >::debug_size();
   if (testbench::enable_idle_sync_mode && that->remaining_ccs_data_in != 0) {
      cout << "Warning: Testbench input channel 'data_in' not empty. Remaining size: " << that->remaining_ccs_data_in << endl;
   }
   that->remaining_ccs_coeff_addr =  coeff_addr.ac_channel<ac_int<5, false > >::debug_size();
   if (testbench::enable_idle_sync_mode && that->remaining_ccs_coeff_addr != 0) {
      cout << "Warning: Testbench input channel 'coeff_addr' not empty. Remaining size: " << that->remaining_ccs_coeff_addr << endl;
   }
   that->capture_result(result);
}
// ============================================
// Function: exec_test
// --------------------------------------------

void mc_testbench::exec_test( ac_channel<ac_int<10, true > > &data_in,  ac_int<7, true > coeffs[32][4],  ac_channel<ac_int<5, false > > &coeff_addr,  ac_channel<ac_int<19, true > > &result)
{
   #ifndef CCS_SCVERIFY_USE_CCS_BLOCK
   that->cpp_testbench_active.write(true);
   capture_IN(data_in, coeffs, coeff_addr, result);
   test(data_in, coeffs, coeff_addr, result);
   // throttle ac_channel based on number of calls to chan::size() or chan::empty() or chan::nb_read() (but not chan::available()) 
   if (1) {
      int cnt=0;
      if (cnt) std::cout << "mc_testbench.cpp: CONTINUES @ " << sc_time_stamp() << std::endl;
      if (cnt) that->cpp_testbench_active.write(true);
   }
   capture_OUT(data_in, coeffs, coeff_addr, result);
   #else
   #endif
}
