// Process: SC_THREAD run
// Static sensitivity: 

void mc_testbench::run() {
   testbench::enable_idle_sync_mode = false;
   testbench::idle_sync_stable_cycles = 1;
   testbench::data_in_ignore = false;
   testbench::data_in_skip = false;
   testbench::data_in_skip_quiet = false;
   testbench::data_in_skip_once = false;
   testbench::data_in_skip_noerr = false;
   testbench::data_in_array_comp_first = -1;
   testbench::data_in_array_comp_last = -1;
   testbench::data_in_wait_ctrl.clear();
   data_in_capture_count = 0;
   data_in_iteration_count = 0;
   testbench::coeffs_ignore = false;
   testbench::coeffs_skip = false;
   testbench::coeffs_skip_quiet = false;
   testbench::coeffs_skip_once = false;
   testbench::coeffs_skip_noerr = false;
   testbench::coeffs_array_comp_first = -1;
   testbench::coeffs_array_comp_last = -1;
   testbench::coeffs_wait_ctrl.clear();
   coeffs_capture_count = 0;
   coeffs_iteration_count = 0;
   testbench::coeff_addr_ignore = false;
   testbench::coeff_addr_skip = false;
   testbench::coeff_addr_skip_quiet = false;
   testbench::coeff_addr_skip_once = false;
   testbench::coeff_addr_skip_noerr = false;
   testbench::coeff_addr_array_comp_first = -1;
   testbench::coeff_addr_array_comp_last = -1;
   testbench::coeff_addr_wait_ctrl.clear();
   coeff_addr_capture_count = 0;
   coeff_addr_iteration_count = 0;
   testbench::result_ignore = false;
   testbench::result_skip = false;
   testbench::result_skip_quiet = false;
   testbench::result_skip_once = false;
   testbench::result_skip_noerr = false;
   testbench::result_array_comp_first = -1;
   testbench::result_array_comp_last = -1;
   testbench::result_use_mask = false;
   testbench::result_output_mask = ~0;
   testbench::result_wait_ctrl.clear();
   result_capture_count = 0;
   result_iteration_count = 0;
   testbench testbench_inst(sc_argc(), sc_argv());
   main_exit_code = testbench_inst.main();
   cout<<"Info: Execution of user-supplied C++ testbench 'main()' has completed with exit code = " << main_exit_code << endl;
   cout<<endl;
   cout<<"Info: Collecting data completed"<<endl;
   cout<<"   captured "<<data_in_capture_count<<" values of data_in"<<endl;
   cout<<"   captured "<<coeffs_capture_count<<" values of coeffs"<<endl;
   cout<<"   captured "<<coeff_addr_capture_count<<" values of coeff_addr"<<endl;
   cout<<"   captured "<<result_capture_count<<" values of result"<<endl;
   testbench_ended = true;
   testbench_end_event.notify(SC_ZERO_TIME);
}
